#include<bits/stdc++.h>
using namespace std;
int cnt[100010];
int read()
{
    int x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=(x<<3)+(x<<1)+(ch-'0');
        ch=getchar();
    }
    return x;
}
int main()
{
    int n=read();
    for(int i=1;i<=n;i++)
    {
        cnt[read()]++;
    }
    queue<long long> p,q;
    for(int i=1;i<=100000;i++)
    {
        while(cnt[i]--)
        {
            p.push(i);
        }
    }
    long long ans=0;
    for(int i=1;i<n;i++)
    {
        long long x,y;
        if(q.empty()||(!p.empty()&&p.front()<q.front()))
        {
            x=p.front();
            p.pop();
        }
        else
        {
            x=q.front();
            q.pop();
        }
        if(q.empty()||(!p.empty()&&p.front()<q.front()))
        {
            y=p.front();
            p.pop();
        }
        else
        {
            y=q.front();
            q.pop();
        }
        q.push(x+y);
        ans+=x+y;
    }
    printf("%lld",ans);
    return 0;
}
